    /**
     * URL-safe slug (lowercase alphanumerics + hyphens). Auto-generated from `name` if omitted. Unique per scope.
     */
    slug?: string;
    /**
     * Optional player-facing description / terms summary.
     */
    description?: string;
    /**
     * Scope at which this promotion lives. See class doc for resolution rules.
     */
    scopeKind: 'PLATFORM' | 'SUPERVISOR' | 'BRANCH';
